# Worked focus: http-py-retry-budget-amplification — Limit total attempts across nested callers and prevent retry storms, duplicate effects, and load amplification. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_retries_backoff_3(method: str, replayable: bool, attempt: int, maximum_attempts: int) -> dict[str, object]:
    assert isinstance(method, str) and isinstance(attempt, int)
    idempotent = method.upper() in {"GET", "HEAD", "PUT"}
    if not replayable or not idempotent or not 1 <= attempt < maximum_attempts:
        return {"retry": False, "delay_ms": 0}
    delay_ms = min(8_000, 250 * (2 ** (attempt - 1)))
    return {"retry": True, "delay_ms": delay_ms}

